// src/components/shared/SubTaskModal.jsx
import { useState, useEffect } from "react";

const STATUSES = ["To Do", "In Progress", "Done", "Hold"];

export default function SubTaskModal({ subTask, onClose, onSave, loading }) {
  const [form, setForm] = useState(
    subTask
      ? { ...subTask }
      : {
          title: "", status: "To Do", estimateTime: "",
          timeFrom: "", timeTo: "", totalMinutes: "", workDoc: "", reason: "",
        }
  );

  // Auto-calculate totalMinutes from timeFrom/timeTo
  useEffect(() => {
    if (form.timeFrom && form.timeTo) {
      const [fh, fm] = form.timeFrom.split(":").map(Number);
      const [th, tm] = form.timeTo.split(":").map(Number);
      const diff = (th * 60 + tm) - (fh * 60 + fm);
      if (diff > 0) setForm(f => ({ ...f, totalMinutes: String(diff) }));
    }
  }, [form.timeFrom, form.timeTo]);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  return (
    <div
      className="modal-overlay"
      onClick={e => e.target === e.currentTarget && onClose()}
    >
      <div className="modal animate-scaleIn">
        {/* Header */}
        <div className="modal-header">
          <div>
            <div className="modal-title">
              {subTask ? "✏️ Edit Sub-task" : "➕ Add Sub-task"}
            </div>
            <p className="text-sm text-gray" style={{ marginTop: 3 }}>
              {subTask ? "Update the sub-task details below." : "Fill in the details for this sub-task."}
            </p>
          </div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        {/* Body */}
        <div className="modal-body">
          <div className="form-grid">
            {/* Title — full width */}
            <div className="form-group full">
              <label className="form-label">Sub-task Title *</label>
              <textarea
                className="form-textarea"
                rows={2}
                value={form.title}
                onChange={e => set("title", e.target.value)}
                placeholder="Describe this sub-task…"
              />
            </div>

            {/* Status */}
            <div className="form-group">
              <label className="form-label">Status</label>
              <select className="form-select" value={form.status} onChange={e => set("status", e.target.value)}>
                {STATUSES.map(s => <option key={s}>{s}</option>)}
              </select>
            </div>

            {/* Estimate */}
            <div className="form-group">
              <label className="form-label">Estimate Time</label>
              <input
                className="form-input"
                value={form.estimateTime}
                onChange={e => set("estimateTime", e.target.value)}
                placeholder="e.g. 1 Hour"
              />
            </div>

            {/* Time From */}
            <div className="form-group">
              <label className="form-label">From</label>
              <input
                className="form-input"
                type="time"
                value={form.timeFrom}
                onChange={e => set("timeFrom", e.target.value)}
              />
            </div>

            {/* Time To */}
            <div className="form-group">
              <label className="form-label">To</label>
              <input
                className="form-input"
                type="time"
                value={form.timeTo}
                onChange={e => set("timeTo", e.target.value)}
              />
            </div>

            {/* Minutes Logged */}
            <div className="form-group">
              <label className="form-label">Minutes Logged</label>
              <input
                className="form-input"
                type="number"
                min="0"
                value={form.totalMinutes}
                onChange={e => set("totalMinutes", e.target.value)}
                placeholder="Auto-calculated or enter manually"
              />
            </div>

            {/* Work Doc */}
            <div className="form-group full">
              <label className="form-label">Work Document / Link</label>
              <input
                className="form-input"
                value={form.workDoc}
                onChange={e => set("workDoc", e.target.value)}
                placeholder="https://drive.google.com/…"
              />
            </div>

            {/* Hold Reason */}
            {form.status === "Hold" && (
              <div className="form-group full">
                <label className="form-label">Reason for Hold</label>
                <textarea
                  className="form-textarea"
                  rows={2}
                  value={form.reason}
                  onChange={e => set("reason", e.target.value)}
                  placeholder="Explain why this is on hold…"
                />
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="modal-footer">
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
          <button
            className="btn btn-primary"
            onClick={() => onSave(form)}
            disabled={loading || !form.title.trim()}
          >
            {loading ? "Saving…" : subTask ? "Update Sub-task" : "Add Sub-task"}
          </button>
        </div>
      </div>
    </div>
  );
}
